import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Simplest case
  it.todo("empty item list → premium 5 G (only processing fee)");

  // Base premiums per item type
  it.todo("single sword → premium 105 G (100 base + 5 fee)");
  it.todo("single amulet → premium 65 G (60 base + 5 fee)");
  it.todo("single staff → premium 85 G (80 base + 5 fee)");
  it.todo("single potion → premium 45 G (40 base + 5 fee)");

  // Components
  it.todo("single rune → premium 30 G (25 base + 5 fee)");
  it.todo("2 runes → premium 55 G (50 base + 5 fee)");

  // Block discount for 3 alike components
  it.todo("3 runes → premium 65 G (60 base via block + 5 fee)");
  it.todo("4 runes → premium 105 G (100 base, no block + 5 fee)");
  it.todo("7 runes → premium 180 G (175 base + 5 fee)");

  // Alike means same type
  it.todo("2 runes + 1 moonstone → premium 80 G (75 base, no block + 5 fee)");
  it.todo("3 runes + 3 moonstones → premium 125 G (120 base, two blocks + 5 fee)");

  // First insurance surcharge (per item, +10%)
  it.todo("newcomer single sword (no previous contract) → first insurance applies to item; premium 115 G (100 + 10 + 5)");

  // Cursed surcharge (+50% of item's base premium)
  it.todo("newcomer cursed sword (steel, enchantment 3) → premium 165 G (100 base + 50 curse + 10 first insurance + 5 fee)");

  // High enchantment surcharge (≥5 → +30%)
  it.todo("sword with enchantment 5 → high-enchantment surcharge applies (130 + 10 first + 5 = 145 G for newcomer)");
  it.todo("sword with enchantment 4 → no high-enchantment surcharge (100 + 10 first + 5 = 115 G for newcomer)");
  it.todo("cursed sword with enchantment 5 → both curse and high-enchantment surcharges apply");

  // Loyalty discount (≥2 years → -20% on policy base premium)
  it.todo("loyal customer (exactly 2 years) single sword → loyalty discount applies");

  // Follow-up contract discount (-15% on policy base premium)
  it.todo("second quote for same customer → follow-up contract discount applies");

  // Modifier scope on multi-item policies
  it.todo("policy with cursed sword + plain amulet → cursed surcharge only on sword (210 G before fee)");

  // Rounding in MHPCO's favor (premium rounded up)
  it.todo("premium calculation yielding 197.5 G → final premium 198 G (rounded up)");

  // Integration examples
  it.todo("newcomer with cursed sword → premium 165 G");
  it.todo("long-standing customer's second contract with cursed sword enchantment 7 → premium 160 G");

  // ---- Claim processing ----

  // Standard reimbursement
  it.todo("regular sword (steel, enchantment 3), damage 500 G → payout 400 G (500 - 100 deductible)");
  it.todo("rune damaged (insurance value 250 G), damage 200 G → payout 100 G (no special clause)");

  // High enchantment clause (≥8 → 50% reimbursement)
  it.todo("steel sword, enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");

  // Dragon material clause (full reimbursement)
  it.todo("dragon-material sword, enchantment 5, damage 800 G → payout 700 G (full minus deductible)");

  // Both clauses → 50% rule wins
  it.todo("dragon-material sword, enchantment 9, damage 1000 G → payout 400 G");
  it.todo("dragon-material sword, enchantment exactly 8, damage 1000 G → payout 400 G");

  // Deductible per damage event
  it.todo("dragon attack damages sword (500 G) and amulet (300 G) → payout 600 G (deductible per item)");

  // Multiple items of same type
  it.todo("policy covers two swords → insurance sum 2000 G, cap 4000 G");
  it.todo("dragon attack damages both swords (two damage entries) → each treated separately with own deductible");
  it.todo("damages array has more entries of a type than policy covers → CLI exits non-zero");

  // Cap exhaustion
  it.todo("policy covers sword + amulet → insurance sum 1600 G, cap 3200 G");
  it.todo("cursed sword → cap 2000 G (based on unmodified insurance value, not modified premium)");
  it.todo("policy covers sword + 3 runes (block) → insurance sum 1750 G (block discount affects premium only)");
  it.todo("sword cap 2000 G, two claims of 1500 G each → first payout 1400 G, second 600 G");

  // Rounding payout (down, in MHPCO's favor)
  it.todo("payout calculation yielding 350.5 G → final payout 350 G (rounded down)");

  // Edge cases — errors
  it.todo("quote with unknown item type → CLI exits non-zero, error to stderr, no results");
  it.todo("claim references damage with item not in policy → CLI exits non-zero");
  it.todo("claim damage with negative amount → CLI exits non-zero");
});

