import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Simplest case
  it("empty item list → premium 5 G (only processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });

  // Base premiums per item type
  it("single sword (newcomer) → premium 115 G (100 base + 10 first insurance + 5 fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it.todo("single amulet → premium 65 G (60 base + 5 fee)");
  it.todo("single staff → premium 85 G (80 base + 5 fee)");
  it.todo("single potion → premium 45 G (40 base + 5 fee)");

  // Components
  it.todo("single rune → premium 30 G (25 base + 5 fee)");
  it.todo("2 runes → premium 55 G (50 base + 5 fee)");

  // Block discount for 3 alike components
  it.todo("3 runes → premium 65 G (60 base via block + 5 fee)");
  it.todo("4 runes → premium 105 G (100 base, no block + 5 fee)");
