      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 60 }] });
  });

  // Block discount for 3 alike components
  it("3 runes (newcomer) → premium 71 G (60 base via block + 6 first insurance + 5 fee)", () => {
