type Item = { type: string };
type Step = { op: "quote"; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const COMPONENT_BASE = 25;
const BLOCK_SIZE = 3;
const BLOCK_BASE = 60;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const componentBlockPrice = (count: number): number => {
  if (count === BLOCK_SIZE) return BLOCK_BASE;
  return count * COMPONENT_BASE;
};

const baseTotalForItems = (items: Item[]): number => {
  const componentCounts = new Map<string, number>();
  let total = 0;
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
    } else {
      total += BASE_PREMIUMS[item.type];
    }
  }
  for (const count of componentCounts.values()) {
    total += componentBlockPrice(count);
  }
  return total;
};

const quoteItems = (items: Item[]): number => {
  const base = baseTotalForItems(items);
  const firstInsuranceSurcharge = base * FIRST_INSURANCE_SURCHARGE_RATE;
  return Math.ceil(base + firstInsuranceSurcharge + PROCESSING_FEE);
};

export const runScenario = (input: Scenario): { results: { premium: number }[] } => {
  const results = input.steps.map((step) => ({ premium: quoteItems(step.items) }));
  return { results };
};

